      {
        "category": "security_boundary",
        "boundary": "Security support for Angular 18 ends 21 Nov 2025. Continuing to run the current version would leave the application without security patches, violating internal security policies.",
        "severity": "blocking",
        "source_facts": [
          "Issue description: support for security updates ended on 21.11.2025 for Angular 18"
        ]
      },
      {
        "category": "testing_constraint",
        "boundary": "The test stack (Karma 6.4.3, Playwright 1.44.1) was aligned with Angular 18. Some test utilities may need updates to work with Angular 19 and the new TypeScript version.",
        "severity": "caution",
        "source_facts": [
          "tech_versions.json: Karma 6.4.3",
          "tech_versions.json: Playwright 1.44.1"
        ]
      }
